var Heap = require('heap');
var AStarFinder = require('./AStarFinder');

/**
 * Dijkstra path-finder (bidirectional).
 * @constructor
 * @extends AStarFinder
 * @param {Object} opt
 * @param {boolean} opt.allowDiagonal Whether diagonal movement is allowed.
 *     Deprecated, use diagonalMovement instead.
 * @param {boolean} opt.dontCrossCorners Disallow diagonal movement touching
 *     block corners. Deprecated, use diagonalMovement instead.
 * @param {DiagonalMovement} opt.diagonalMovement Allowed diagonal movement.
 */
function DijkstraFinder(opt) {
    AStarFinder.call(this, opt);
    this.heuristic = function(dx, dy) {
        return 0;
    };
}

DijkstraFinder.prototype = new AStarFinder();
DijkstraFinder.prototype.constructor = DijkstraFinder;

DijkstraFinder.prototype.findPath = function(startX, startY, endX, endY, grid) {
    var abs = Math.abs, SQRT2 = Math.SQRT2;
    var diagonalMovement = this.diagonalMovement;

    var startNode = grid.getNodeAt(startX, startY);
    var endNode = grid.getNodeAt(endX, endY);

    if (startNode === endNode) {
        return [[startX, startY]];
    }

    // Forward heap: expand from start, keyed by gF
    var fHeap = new Heap(function(a, b) { return a.gF - b.gF; });
    // Backward heap: expand from end, keyed by gB
    var bHeap = new Heap(function(a, b) { return a.gB - b.gB; });

    startNode.gF = 0;
    startNode.openedF = true;
    startNode.opened = true; // for countNodes
    fHeap.push(startNode);

    endNode.gB = 0;
    endNode.openedB = true;
    endNode.opened = true; // for countNodes
    bHeap.push(endNode);

    var mu = Infinity;
    var meetNode = null;

    var neighbors, neighbor, node, ng, i, l, x, y, pathCost;

    while (!fHeap.empty() && !bHeap.empty()) {
        // Termination: if best possible remaining path >= best found, stop
        if (fHeap.peek().gF + bHeap.peek().gB >= mu) {
            break;
        }

        // --- Forward expansion ---
        node = fHeap.pop();
        node.closedF = true;
        node.closed = true; // for countNodes

        neighbors = grid.getNeighbors(node, diagonalMovement);
        for (i = 0, l = neighbors.length; i < l; ++i) {
            neighbor = neighbors[i];
            if (neighbor.closedF) continue;

            x = neighbor.x;
            y = neighbor.y;
            ng = node.gF + ((x - node.x === 0 || y - node.y === 0) ? 1 : SQRT2);

            if (!neighbor.openedF || ng < neighbor.gF) {
                neighbor.gF = ng;
                neighbor.parentF = node;
                if (!neighbor.openedF) {
                    neighbor.openedF = true;
                    neighbor.opened = true; // for countNodes
                    fHeap.push(neighbor);
                } else {
                    fHeap.updateItem(neighbor);
                }
                // Check if backward search has reached this node
                if (neighbor.gB !== undefined) {
                    pathCost = ng + neighbor.gB;
                    if (pathCost < mu) {
                        mu = pathCost;
                        meetNode = neighbor;
                    }
                }
            }
        }

        if (fHeap.empty() || bHeap.empty()) break;
        if (fHeap.peek().gF + bHeap.peek().gB >= mu) break;

        // --- Backward expansion ---
        node = bHeap.pop();
        node.closedB = true;
        node.closed = true; // for countNodes

        neighbors = grid.getNeighbors(node, diagonalMovement);
        for (i = 0, l = neighbors.length; i < l; ++i) {
            neighbor = neighbors[i];
            if (neighbor.closedB) continue;

            x = neighbor.x;
            y = neighbor.y;
            ng = node.gB + ((x - node.x === 0 || y - node.y === 0) ? 1 : SQRT2);

            if (!neighbor.openedB || ng < neighbor.gB) {
                neighbor.gB = ng;
                neighbor.parentB = node;
                if (!neighbor.openedB) {
                    neighbor.openedB = true;
                    neighbor.opened = true; // for countNodes
                    bHeap.push(neighbor);
                } else {
                    bHeap.updateItem(neighbor);
                }
                // Check if forward search has reached this node
                if (neighbor.gF !== undefined) {
                    pathCost = neighbor.gF + ng;
                    if (pathCost < mu) {
                        mu = pathCost;
                        meetNode = neighbor;
                    }
                }
            }
        }
    }

    if (!meetNode) return [];

    // Reconstruct path: forward from start to meetNode, then backward to end
    var path = [];
    var curr = meetNode;
    while (curr) {
        path.unshift([curr.x, curr.y]);
        curr = curr.parentF;
    }
    curr = meetNode.parentB;
    while (curr) {
        path.push([curr.x, curr.y]);
        curr = curr.parentB;
    }

    return path;
};

module.exports = DijkstraFinder;

