    AStarFinder.call(this, opt);
    this.heuristic = function(dx, dy) {
        return 0;
    };
}

DijkstraFinder.prototype = new AStarFinder();
DijkstraFinder.prototype.constructor = DijkstraFinder;

/**
 * Override findPath to use goal-directed tie-breaking.
 * Primary sort key: g (Dijkstra optimality preserved).
 * Tie-break: prefer nodes with smaller manhattan distance to goal.
 * This guides exploration toward the goal without affecting path cost.
 */
